# Python 3.11+
"""Domain entities, enums and errors for the parking lot system.

The one entity with real behaviour is ParkingSpot, a tiny STATE MACHINE ‚Äî the
only place allowed to change a spot's status, so the service can never occupy or
free a spot illegally.
"""

from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum, IntEnum


# ‚îÄ‚îÄ ENUMS ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
class SpotSize(IntEnum):
    # IntEnum so "does this spot fit the vehicle" is just spot.size >= required.
    SMALL = 1
    MEDIUM = 2
    LARGE = 3


class VehicleType(IntEnum):
    MOTORCYCLE = 1
    CAR = 2
    TRUCK = 3


# A vehicle needs a spot at least as big as this. Motorcycle fits anything,
# a truck needs a large spot.
REQUIRED_SIZE: dict[VehicleType, SpotSize] = {
    VehicleType.MOTORCYCLE: SpotSize.SMALL,
    VehicleType.CAR: SpotSize.MEDIUM,
    VehicleType.TRUCK: SpotSize.LARGE,
}


class SpotStatus(Enum):
    AVAILABLE = "AVAILABLE"
    OCCUPIED = "OCCUPIED"
    OUT_OF_SERVICE = "OUT_OF_SERVICE"


class TicketStatus(Enum):
    ACTIVE = "ACTIVE"
    CLOSED = "CLOSED"


# ‚îÄ‚îÄ ERRORS ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
class ParkingError(Exception):
    pass


class LotFullError(ParkingError):
    pass


class UnknownTicketError(ParkingError):
    pass


class TicketAlreadyClosedError(ParkingError):
    pass


class IllegalSpotTransitionError(ParkingError):
    pass


# ‚îÄ‚îÄ ENTITIES ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
@dataclass(frozen=True)
class Vehicle:
    # Frozen value object: a vehicle's plate and type don't change while parked.
    plate: str
    type: VehicleType

    @property
    def required_size(self) -> SpotSize:
        return REQUIRED_SIZE[self.type]


@dataclass
class ParkingSpot:
    """One spot as a STATE MACHINE: AVAILABLE -> OCCUPIED -> AVAILABLE.

    Only this class flips its own status, so the service can never skip a step.
    """
    id: str
    floor: int
    size: SpotSize
    status: SpotStatus = SpotStatus.AVAILABLE

    def is_available(self) -> bool:
        return self.status == SpotStatus.AVAILABLE

    def fits(self, required: SpotSize) -> bool:
        return self.size >= required

    def occupy(self) -> None:
        # Guard the from-state so a taken spot can never be double-occupied.
        if self.status != SpotStatus.AVAILABLE:
            raise IllegalSpotTransitionError(
                f"spot {self.id} cannot be occupied from {self.status.value}"
            )
        self.status = SpotStatus.OCCUPIED

    def release(self) -> None:
        # Safe to call twice: only an OCCUPIED spot frees; otherwise a no-op.
        if self.status == SpotStatus.OCCUPIED:
            self.status = SpotStatus.AVAILABLE

    def out_of_service(self) -> None:
        self.status = SpotStatus.OUT_OF_SERVICE


@dataclass
class ParkingFloor:
    # A floor OWNS its spots (composition) ‚Äî they can't exist without it.
    id: int
    spots: dict[str, ParkingSpot] = field(default_factory=dict)

    def fitting_available(self, required: SpotSize) -> list[ParkingSpot]:
        return [s for s in self.spots.values() if s.is_available() and s.fits(required)]


@dataclass
class Ticket:
    # The glue object: ties a vehicle to the exact spot it holds, with timing so
    # the fee can be computed on exit.
    id: str
    spot_id: str
    floor: int
    vehicle: Vehicle
    entry_time: datetime
    exit_time: datetime | None = None
    fee: float | None = None
    status: TicketStatus = TicketStatus.ACTIVE

# Python 3.11+
"""The extensibility SEAMS (Strategy pattern).

Two genuine policies the business will want to vary:
  - AllocationStrategy: WHICH spot to give a vehicle.
  - FeeStrategy: HOW MUCH to charge on exit.
The ParkingService depends on these abstractions, never on a concrete rule, so a
new policy is a new class with zero core changes (Open/Closed).
"""

import math
from abc import ABC, abstractmethod
from datetime import datetime

from models import ParkingFloor, ParkingSpot, SpotSize


# ‚îÄ‚îÄ allocation: which spot to hand out ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
class AllocationStrategy(ABC):
    @abstractmethod
    def select(self, floors: list[ParkingFloor], required: SpotSize) -> ParkingSpot | None:
        ...


class NearestFirstAllocation(AllocationStrategy):
    """Lowest floor, then lowest spot id ‚Äî get the driver in fastest."""

    def select(self, floors: list[ParkingFloor], required: SpotSize) -> ParkingSpot | None:
        best: ParkingSpot | None = None
        for floor in sorted(floors, key=lambda f: f.id):
            for spot in floor.fitting_available(required):
                if best is None or spot.id < best.id:
                    best = spot
            if best is not None:
                return best   # first floor with any fitting spot wins (nearest)
        return None


class BestFitAllocation(AllocationStrategy):
    """Smallest fitting spot anywhere ‚Äî don't waste a LARGE spot on a motorcycle."""

    def select(self, floors: list[ParkingFloor], required: SpotSize) -> ParkingSpot | None:
        candidates = [s for f in floors for s in f.fitting_available(required)]
        if not candidates:
            return None
        # smallest fitting size first; tie-break by id for determinism
        return min(candidates, key=lambda s: (s.size, s.id))


# ‚îÄ‚îÄ fee: how much to charge ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
class FeeStrategy(ABC):
    @abstractmethod
    def compute(self, entry: datetime, exit: datetime) -> float:
        ...


class HourlyFeeStrategy(FeeStrategy):
    """Flat rate per started hour, minimum one hour."""

    def __init__(self, rate_per_hour: float = 2.0) -> None:
        self.rate_per_hour = rate_per_hour

    def compute(self, entry: datetime, exit: datetime) -> float:
        seconds = max(0.0, (exit - entry).total_seconds())
        hours = max(1, math.ceil(seconds / 3600))   # min one hour, round up
        return hours * self.rate_per_hour
